import React, {useEffect, useState} from "react";
import {useLocation} from "react-router-dom";
import ReactPlayer from "react-player";
// import webproject1 from "../../resources/web-project-1.png";
import Modal from "react-modal";
const customStyles = {
    content : {
        top                   : '50%',
        left                  : '50%',
        right                 : 'auto',
        bottom                : 'auto',
        marginRight           : '-50%',
        transform             : 'translate(-50%, -50%)',
        width:"90%",
        height:"60%"
    }
};
const config =
    [
        {
            projectTitle:"Helicopter Simulation",
            projectURL:"https://youtu.be/qxyVnWaRFz8",
            languageUsed:"C++ and OpenGL",
            repoURL:"https://github.com/DMZnoo/Helicopter"
        },
        {
            projectTitle:"Solar System Simulation",
            projectURL:"https://youtu.be/osDyGag0H-E",
            languageUsed:"C++ and OpenGL",
            repoURL:"https://github.com/DMZnoo/Solar_System"
        }
    ];
const SoftwareProjects = () =>
{
    const location = useLocation();
    const [isProfession,SetProfession] = useState("");
    const [isShown, SetIsShown] = useState([]);
    const [isPlayable,SetPlayable] = useState([]);
    const [modalIsOpen,setIsOpen] = useState([]);
    const grid = [];
    useEffect((grid)=>{
        SetProfession(location.state.prof);

        for(let i =0; i < 2;i++)
        {
            alert(i);
            SetIsShown(isShown => [...isShown,{i:false}]);
            grid.push(
                <div className="cell"
                     onMouseEnter={() => detectMouse(i,true)}
                     onMouseLeave={() => detectMouse(i,false)}
                     onClick={()=>detectMouse(i,true)}
                >
                    {!modalIsOpen.i && (
                        <div>
                            <button
                                className="ui orange inverted button demo1"
                                onClick={() => setIsOpen({i: true})}
                                style={{opacity:isShown.i ? 1:0,transition: "opacity 1s",zIndex:"5"}}>Learn More</button>
                        </div>
                    )

                    }
                    <ReactPlayer
                        url="https://youtu.be/qxyVnWaRFz8"
                        width='40vw'
                        height='40vh'
                        volume={1}
                        muted={true}
                        loop={false}
                        playing={isPlayable.i===true ? false:true}
                        // controls={isPlayable==1 ? 0 : 1}
                        controls={true}
                    ></ReactPlayer>

                    {modalIsOpen.i && (
                        <Modal
                            isOpen={modalIsOpen.i}
                            onRequestClose={()=>setIsOpen({i:false})}
                            style={customStyles}
                            contentLabel="Example Modal"

                        >
                            <div className="ui segment" style={{width:"100%",height:"100%",zIndex:"6"}}>
                                <h2>Helicopter Simulation</h2>
                                <h4>Written in: C++ and OpenGL </h4>
                                <div className="grid">
                                    <div className="cell">
                                        <p>Check out the repository: </p>
                                    </div>
                                    <div className="cell">
                                        <a href="https://github.com/DMZnoo/Helicopter" target="_blank">REPO</a>
                                    </div>
                                </div>
                            </div>
                            <div className="ui vertical segment">
                                <button className="ui red inverted button" onClick={()=>closeModal('vid1')}>close</button>
                            </div>

                        </Modal>
                    )

                    }
                </div>
            );
        }

    },[location]);
    function detectMouse(n,bool)
    {
        SetIsShown({[n]:bool});
        SetPlayable({[n]:bool});
    }
    function closeModal(modalN){
        SetIsShown({
            [modalN]:true
        });
        SetPlayable({
            [modalN]:true
        });
        setIsOpen({
            [modalN]:false
        });
    }


    return (
        grid
    )

};
export default SoftwareProjects;
